  ('investigation-a6b1e630-moex-00140', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', '有關地方自治，下列敘述何者錯誤？', '["實施地方自治之組織須具備法人性質，有獨立法人格", "原住民族之地方自治已制定法律予以保障", "地方自治團體須具備處理地方事務之權力", "地方事務範圍內，地方自治團體可自主決定處理方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
  ('investigation-a6b1e630-moex-00141', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', '依中央法規標準法之規定，下列何者不是法規適用之原則？', '["未經修正之舊特別法優先於修正後之新普通法", "案件受理後如經修法，原則上適用修法後之新法規", "案件受理後如經修法，原則上適用有利於當事人之法規", "準用之法規如經修正，應繼續準用修正前之舊法規"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
