  ('investigation-a6b1e630-moex-00143', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', '依司法院大法官解釋，下列有關「權力分立」原則之敘述，何者正確？', '["立法院不能將行政院對於國家通訊傳播委員會之人事決定權予以實質剝奪或逕行取而代之", "行政院得就涉及國家重要政策變更之法定預算，依其合義務之裁量，自行裁減經費或變動執行", "為使監察院行使職權、發揮功能，立法院有義務通過總統就監察委員之提名人選", "立法院調查權之行使，以文件調閱為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
  ('investigation-a6b1e630-moex-00144', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', 'A股份有限公司股東甲，於本年度A公司之股東大會行使表決權時，下列敘述何者正確？', '["甲若將A公司之股東會之委託書交給代理人後，即無法再親自出席", "甲若以電子投票行使表決權，即無法再親自出席", "甲若以電子投票行使表決權，即視為親自出席股東會，所以仍得提出臨時動議", "甲若以電子投票後再委託代理人出席，以委託代理人出席行使之表決權為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
  ('investigation-a6b1e630-moex-00145', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', '勞動基準法第22條之1關於派遣事業單位積欠派遣勞工工資之規定，下列敘述何者正確？', '["派遣勞工僅得向派遣事業單位請求給付積欠工資", "經主管機關處罰或依第27條規定限期令其給付而屆期未給付者，派遣勞工亦得請求要派單位給付", "要派單位應自派遣勞工請求之日起15日內給付之", "要派單位依規定給付者，不得向派遣事業單位求償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
  ('investigation-a6b1e630-moex-00146', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', '給付遲延，乃債務不履行類型之一。關於給付遲延，下列敘述何者錯誤？', '["給付有確定期限者，債務人自期限屆滿時起，負遲延責任", "因不可歸責於債務人之事由，致未為給付者，債務人不負遲延責任", "遲延後之給付，於債權人無利益者，債權人得拒絕其給付，並得請求賠償因不履行而生之損害", "遲延之債務，以支付金錢為標的者，債權人僅得請求遲延利息"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
