  ('investigation-a6b1e630-moex-00148', 'investigation-a6b1e630', 'investigation-a6b1e630-moex-111-44c4f898', 'sub-investigation-a6b1e630-02', NULL, 'single_choice', '甲乙為同居多年之伴侶，並共同育有6歲大之女兒丙。然甲有酗酒習慣，且酒後常辱罵以及毆打乙。試問 乙得否向法院聲請保護令禁止甲接觸丙？', '["否，因為丙還未成年", "否，因為丙並非家庭暴力之被害人", "可以，因為丙為被害人之直系血親", "可以，因為丙為家庭暴力防治法中目睹家庭暴力之兒童"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:44+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "413", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "電子科學組"}'::jsonb, NULL),
